sys_script_include.script:
var VmsReferenceQualifier = Class.create();
VmsReferenceQualifier.prototype = {
    initialize: function() {},

    /**
     * Returns an encoded query to filter facility_inventory records by branch.
     * Handles multiple contexts:
     * 1. RITM form (after submission) - uses current.variables
     * 2. Cart item (during ordering) - looks up sc_cart_item by sysparm_id
     * 3. Fallback - shows all records if branch cannot be determined
     */
    getFacilityFilter: function() {
        var branch = '';

        // Approach 1: Try current.variables (works on RITM form after submission)
        try {
            if (typeof current !== 'undefined' && current && current.variables && current.variables.branch) {
                branch = current.variables.branch.toString();
            }
        } catch(e) {
            // current.variables may not be available in MRVS popup context
        }

        // Approach 2: Look up from cart item via RP parameter (during ordering)
        if (!branch) {
            try {
                var cartId = RP.getParameterValue('sysparm_id');
                if (cartId) {
                    // Try sc_cart_item first (ordering context)
                    var cartItem = new GlideRecord('sc_cart_item');
                    if (cartItem.get(cartId) && cartItem.variables.branch) {
                        branch = cartItem.variables.branch.toString();
                    }

                    // Try sc_req_item (viewing/editing submitted request)
                    if (!branch) {
                        var ritm = new GlideRecord('sc_req_item');
                        if (ritm.get(cartId) && ritm.variables.branch) {
                            branch = ritm.variables.branch.toString();
                        }
                    }
                }
            } catch(e) {
                // RP may not be available in all contexts
            }
        }

        // Return the encoded query filter
        if (branch) {
            return 'branch=' + branch;
        }

        // No branch selected - show no facilities (user must select a branch first)
        return 'sys_id=NULL';
    },

    type: 'VmsReferenceQualifier'
};
